function.body:
v_QtyIn  NUMBER;
  v_Acum   NUMBER;
  v_result NUMBER;
BEGIN

  v_QtyIn:= p_amount;
  v_Acum :=0;

  /*while v_QtyIn >  v_Acum loop
	--raise notice 'v_Acum %', v_Acum;
 	v_Acum:= v_Acum +1;
   end loop;
   */

   IF (v_QtyIn>=0.5 AND v_QtyIn<=1) THEN
	v_QtyIn:=1;
   ELSE

	   SELECT COALESCE((select case when (v_QtyIn  - trunc(v_QtyIn,0)) >=0.5  then round(v_QtyIn) else trunc(v_QtyIn,0) end  from dual),0)
	   INTO v_Acum
	   FROM DUAL;  
   END IF;

   return v_Acum;
END SSMRPS_GET_QTY2
